-- BAD: price as INTEGER loses decimal places
CREATE TABLE products (
  id INTEGER PRIMARY KEY,
  name TEXT,
  price INTEGER  -- $49.99 becomes $49!
);

-- GOOD: price as DECIMAL keeps cents
CREATE TABLE products (
  id INTEGER PRIMARY KEY,
  name TEXT,
  price DECIMAL(10, 2)  -- 10 digits total, 2 after the decimal
);
